from concurrent import futures
import time
import uuid
import grpc

import auth_data_pb2
import auth_data_pb2_grpc


USERS = {
    "alice": {"password": "password123", "user_id": "u1"},
    "bob": {"password": "secret456", "user_id": "u2"},
}

TOKENS = {}

DATA_STORE = {
    "resource-1": {"owner": "u1", "data": "Alice private data for resource-1"},
    "resource-2": {"owner": "u2", "data": "Bob private data for resource-2"},
    "resource-3": {"owner": "u1", "data": "Shared analytics payload for resource-3"},
}


class AuthService(auth_data_pb2_grpc.AuthServiceServicer):
    def Login(self, request, context):
        user = USERS.get(request.username)
        if not user or user["password"] != request.password:
            return auth_data_pb2.LoginResponse(
                success=False,
                token="",
                message="Invalid username or password",
            )

        token = str(uuid.uuid4())
        TOKENS[token] = user["user_id"]

        return auth_data_pb2.LoginResponse(
            success=True,
            token=token,
            message="Login successful",
        )

    def ValidateToken(self, request, context):
        user_id = TOKENS.get(request.token)
        if not user_id:
            return auth_data_pb2.ValidateTokenResponse(
                valid=False,
                user_id="",
                message="Invalid or expired token",
            )

        return auth_data_pb2.ValidateTokenResponse(
            valid=True,
            user_id=user_id,
            message="Token is valid",
        )


class DataService(auth_data_pb2_grpc.DataServiceServicer):
    def GetData(self, request, context):
        user_id = TOKENS.get(request.token)
        if not user_id:
            return auth_data_pb2.GetDataResponse(
                success=False,
                data="",
                message="Unauthorized: invalid token",
            )

        resource = DATA_STORE.get(request.resource_id)
        if not resource:
            return auth_data_pb2.GetDataResponse(
                success=False,
                data="",
                message="Resource not found",
            )

        if resource["owner"] != user_id:
            return auth_data_pb2.GetDataResponse(
                success=False,
                data="",
                message="Forbidden: access denied",
            )

        return auth_data_pb2.GetDataResponse(
            success=True,
            data=resource["data"],
            message="Data retrieved successfully",
        )


def serve():
    server = grpc.server(futures.ThreadPoolExecutor(max_workers=10))
    auth_data_pb2_grpc.add_AuthServiceServicer_to_server(AuthService(), server)
    auth_data_pb2_grpc.add_DataServiceServicer_to_server(DataService(), server)
